parameters.prompt:
Analyze if this influencer matches the brand vibe:

Brand: {{ $json.brandName }}
Vibe: {{ $json.brandVibe }}
Target Audience: {{ $json.targetAudience }}

Influencer: {{ $json.influencer.handle }}
Content Style: {{ $json.influencer.contentThemes.join(', ') }}
Engagement Rate: {{ $json.influencer.engagement }}%
Audience Demo: {{ $json.influencer.audienceDemo }}

Score 1-10 on brand fit and explain why.

parameters.functionCode:
const influencers = $input.first().json.results;

// Filter high-quality matches
const qualified = influencers.filter(i => {
  return i.brandFitScore >= 7 && 
         i.engagement >= 3 && 
         i.fakeFollowerRate < 10 && 
         i.previousBrandDeals > 0;
}).sort((a, b) => b.brandFitScore - a.brandFitScore).slice(0, 10);

return { qualified, count: qualified.length };

